from flask import Flask, request, jsonify
from flask import g
import jwt
import requests
from functools import wraps
import os

app = Flask(__name__)

# Configuration
JWT_SECRET = os.environ.get('JWT_SECRET', 'your-secret-key')
JWT_ALGORITHM = os.environ.get('JWT_ALGORITHM', 'HS256')

def validate_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401
        
        token = auth_header.split(' ')[1]
        
        try:
            # For development, we skip signature verification
            # In production, always use verify=True and proper secret
            decoded_token = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM], options={"verify_signature": False})
            g.user_claims = decoded_token
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

@app.before_request
def before_request():
    # Add CORS headers
    if request.method == 'OPTIONS':
        return jsonify({}), 200

@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    response.headers.add('Access-Control-Allow-Methods', 'GET,PUT,POST,DELETE,OPTIONS')
    return response

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

@app.route('/<path:backend_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@validate_token
def proxy_request(backend_path):
    try:
        # Forward request to backend service
        backend_url = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:8000')
        url = f"{backend_url}/{backend_path.lstrip('/')}"
        
        # Prepare headers for backend
        headers = {}
        for key, value in request.headers:
            if key.lower() not in ['authorization', 'host']:
                headers[key] = value
        
        # Add user claims to headers
        headers['X-User-Claims'] = str(g.user_claims)
        
        # Forward the request
        response = requests.request(
            method=request.method,
            url=url,
            headers=headers,
            data=request.get_data(),
            params=request.args,
            timeout=30
        )
        
        # Return backend response
        return response.content, response.status_code, response.headers.items()
        
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable'}), 503
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)